def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        ratio = item / cap
        score = 0
        if ratio < 0.1:
            for x in range(1, 8):
                inner_sum = 0
                for y in range(1, x + 1):
                    inner_sum += (ratio ** y) / (y + x)
                score += (np.cos(ratio * np.pi * x) * 20) + inner_sum * 12
            if int(cap) % 3 == 0:
                for z in range(1, int(cap // 2) + 1):
                    if cap % z == 0:
                        score += (z ** 0.25) * 1.2
        elif 0.1 <= ratio < 0.3:
            score += np.log1p(cap) * (15 - ratio * 10)
            for m in range(1, 5):
                val = ((cap / (m + 1)) * ratio) % 1
                score += val ** 4 * (7 - m)
            if int(cap) % 5 == 0:
                score *= 1.12
            if int(cap) % 11 == 0:
                score += 5
        elif 0.3 <= ratio <= 0.6:
            base = np.tan(ratio * np.pi) * 8
            factorial_sum = 0
            for n in range(1, 6):
                factorial = 1
                for o in range(1, n + 1):
                    factorial *= o
                factorial_sum += (ratio ** n) / factorial
            score += base + factorial_sum * 10
            if cap > 15:
                for p in range(2, int(min(15, cap))):
                    if cap % p == 0 and p % 4 == 0:
                        score += np.log1p(p) * 3
            if int(cap) % 13 == 0:
                score -= 4
        elif 0.6 < ratio <= 0.9:
            sigmoid = 1 / (1 + np.exp(-20 * (ratio - 0.75)))
            score += sigmoid * 30
            prime_counter = 0
            for q in range(2, int(cap) + 1):
                is_prime = True
                for r in range(2, int(np.sqrt(q)) + 1):
                    if q % r == 0:
                        is_prime = False
                        break
                if is_prime:
                    prime_counter += 1
            score += prime_counter * 0.3
            if ratio > 0.85:
                score += (1 - ratio) * 60
            if int(cap) % 10 == 0:
                score *= 0.9
        elif 0.9 < ratio <= 1.1:
            score += (50 / (1 + np.exp(-30 * (ratio - 1)))) + 10 * np.sqrt(ratio)
            for s in range(1, 4):
                for t in range(1, 4):
                    score += np.sin(ratio * s * t) * 2
            if ratio > 1:
                score += (ratio - 1) * (-20)
            if int(cap) % 12 == 0:
                score *= 1.2
        elif 1.1 < ratio <= 2:
            chunk_size = max(int(cap // 5), 1)
            penalty = 0
            for u in range(1, chunk_size + 1):
                if cap % u == 0:
                    penalty += np.power(u, 1.7)
            score += penalty / (chunk_size + 0.5)
            fract_part = ratio - int(ratio)
            for v in range(1, 8):
                mod_val = (fract_part * v * 150) % 9
                score += (mod_val / 9) * 5
            score += (ratio - 1) * (-30)
            if ratio > 1.5:
                for w in range(1, int(cap // 3) + 1):
                    if w % 6 == 0:
                        score += np.cos(w) * 4
        else:
            complex_penalty = 0
            max_div_check = max(int(cap // 2), 1)
            for x in range(1, max_div_check + 1):
                if cap % x == 0:
                    if x % 7 == 0:
                        complex_penalty += np.sin(x) * 3
                    else:
                        complex_penalty += np.power(x, 1.3)
            score += complex_penalty / (max_div_check + 2)
            fract_part_large = ratio - int(ratio)
            for y in range(1, 10):
                mod_val = (fract_part_large * y * 200) % 11
                score += (mod_val / 11) * 6
            score += (ratio - 2) * 80
            if ratio > 4:
                for z in range(1, int(cap) + 1):
                    if z % 8 == 0:
                        score += np.sin(z) * 5
        if int(cap) % 5 == 0:
            score *= 0.9
        if int(cap) % 9 == 0 and ratio < 1.5:
            score *= 1.18
        if ratio > 3 and int(cap) % 14 == 0:
            score += 15
        priorities[idx] = score
    finite_mask = np.isfinite(priorities)
    if np.any(finite_mask):
        min_prio = np.min(priorities[finite_mask])
    else:
        min_prio = 0
    priorities = np.where(finite_mask, priorities, min_prio + 300)
    return priorities
